evaluators.evaluation_logic:
const checkpoints = [];

const tickets = JSON.parse(localStorage.getItem('ticket_types') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const orders = JSON.parse(localStorage.getItem('registration_orders') || '[]');
const conferences = JSON.parse(localStorage.getItem('conferences') || '[]');

// Determine current conference (by current_year or latest start_date as fallback)
const nowYear = (new Date()).getFullYear();
let currentConf = conferences.find(c => c.current_year === nowYear);
if (!currentConf && conferences.length) {
  conferences.sort((a, b) => new Date(b.start_date).getTime() - new Date(a.start_date).getTime());
  currentConf = conferences[0];
}

// Eligible 3-day tickets with workshop credits under or equal to $700
const eligibleTickets = tickets.filter(t => {
  if (!t) return false;
  if (currentConf && t.conference_id && t.conference_id !== currentConf.id) return false;
  if (t.duration_type !== 'three_day') return false;
  if (!t.includes_workshop_credits) return false;
  const price = typeof t.total_price === 'number' ? t.total_price : 0;
  if (price > 700) return false;
  if (t.is_active === false) return false;
  return true;
});

eligibleTickets.sort((a, b) => (a.total_price || 0) - (b.total_price || 0));
const cheapest = eligibleTickets[0];

// Check if cheapest qualifying ticket is in any cart_items
let cartHasCheapest = false;
if (cheapest) {
  cartHasCheapest = cartItems.some(ci => ci.ticket_type_id === cheapest.id && (ci.quantity || 0) > 0);
}

// CP1 (0.5): User added the cheapest qualifying 3-day ticket with workshop credits (≤$700) to the cart
checkpoints.push({ passed: !!cheapest && cartHasCheapest, weight: 0.5 });

// Check if any registration order references a cart that contains the cheapest qualifying ticket
let orderWithCheapest = false;
if (cheapest && orders && orders.length && cartItems && cartItems.length) {
  orderWithCheapest = orders.some(order => {
    const cartId = order && order.cart_id;
    if (!cartId) return false;
    return cartItems.some(ci => ci.cart_id === cartId && ci.ticket_type_id === cheapest.id && (ci.quantity || 0) > 0);
  });
}

// CP2 (0.5): User completed registration using a cart that includes the cheapest qualifying ticket
checkpoints.push({ passed: !!cheapest && orderWithCheapest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('live_sessions') || '[]');
const mySessions = sessions.filter(s => s && s.added_to_my_schedule);

const parseMinutes = (dateTimeStr) => {
  if (!dateTimeStr) return null;
  const d = new Date(dateTimeStr);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
};

// Qualifying sessions: Day 1 or Day 2, between 09:00 and 17:00
const qualifying = mySessions.filter(s => {
  if (!s) return false;
  if (s.day_id !== 'day_1_june_12' && s.day_id !== 'day_2_june_13') return false;
  const mins = parseMinutes(s.start_datetime);
  if (mins === null) return false;
  return mins >= 9 * 60 && mins <= 17 * 60;
});

// CP1 (0.4): At least 4 qualifying sessions in the agenda
checkpoints.push({ passed: qualifying.length >= 4, weight: 0.4 });

// Check for keynote and AI & ML track among qualifying sessions
const hasKeynote = qualifying.some(s => s.session_type === 'keynote' || s.is_keynote);
const hasAiTrack = qualifying.some(s => s.track === 'ai_and_machine_learning');

// CP2 (0.3): Among qualifying sessions, at least one keynote AND at least one AI & ML track session
checkpoints.push({ passed: qualifying.length > 0 && hasKeynote && hasAiTrack, weight: 0.3 });

// Check for non-overlapping start times (no duplicate start_datetime among qualifying)
let uniqueStartTimes = false;
if (qualifying.length > 0) {
  const starts = qualifying.map(s => s.start_datetime).filter(Boolean);
  const unique = new Set(starts);
  uniqueStartTimes = unique.size === starts.length;
}

// CP3 (0.3): At least 4 qualifying sessions and their start times are all distinct
checkpoints.push({ passed: qualifying.length >= 4 && uniqueStartTimes, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('live_sessions') || '[]');

const parseMinutes = (dateTimeStr) => {
  if (!dateTimeStr) return null;
  const d = new Date(dateTimeStr);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
};

// All qualifying Day 1 evening networking events with free refreshments
const allQualifying = sessions.filter(s => {
  if (!s) return false;
  if (s.day_id !== 'day_1_june_12') return false;
  const isNetworkingType = s.session_type === 'networking' || s.session_type === 'social_event' || !!s.is_networking;
  if (!isNetworkingType) return false;
  const hasRefresh = !!s.has_free_refreshments || (Array.isArray(s.perks) && s.perks.indexOf('free_refreshments') !== -1);
  if (!hasRefresh) return false;
  const mins = parseMinutes(s.start_datetime);
  if (mins === null) return false;
  return mins >= 17 * 60;
});

const scheduledQualifying = allQualifying.filter(s => s.added_to_my_schedule);

// CP1 (0.3): User added at least two qualifying evening networking events with free refreshments on Day 1
checkpoints.push({ passed: scheduledQualifying.length >= 2, weight: 0.3 });

// CP2 (0.7): User added all qualifying evening networking events with free refreshments on Day 1
checkpoints.push({ passed: allQualifying.length > 0 && scheduledQualifying.length === allQualifying.length, weight: 0.7 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('live_sessions') || '[]');

const difficultyRank = (level) => {
  const order = { expert: 4, advanced: 3, intermediate: 2, beginner: 1, all_levels: 0, not_applicable: 0 };
  return order[level] || 0;
};

// Eligible Day 2 design thinking workshops (≤180 minutes, ≤$300)
const eligible = sessions.filter(s => {
  if (!s) return false;
  if (s.day_id !== 'day_2_june_13') return false;
  const isWorkshop = s.session_type === 'workshop' || !!s.is_workshop;
  if (!isWorkshop) return false;
  const title = (s.title || '').toLowerCase();
  const desc = (s.description || '').toLowerCase();
  const isDesignThinking = title.includes('design thinking') || desc.includes('design thinking');
  if (!isDesignThinking) return false;
  if (typeof s.duration_minutes === 'number' && s.duration_minutes > 180) return false;
  if (typeof s.price === 'number' && s.price > 300) return false;
  return true;
});

const scheduledEligible = eligible.filter(s => s.added_to_my_schedule);

// CP1 (0.4): User added at least one eligible Day 2 design thinking workshop (≤3h, ≤$300) to their schedule
checkpoints.push({ passed: scheduledEligible.length >= 1, weight: 0.4 });

// Identify highest-difficulty eligible workshop
let highestScheduled = false;
if (eligible.length > 0) {
  eligible.sort((a, b) => difficultyRank(b.difficulty_level) - difficultyRank(a.difficulty_level));
  const top = eligible[0];
  highestScheduled = !!top && !!top.added_to_my_schedule;
}

// CP2 (0.6): User added the highest-difficulty eligible design thinking workshop
checkpoints.push({ passed: eligible.length > 0 && highestScheduled, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const exhibitors = JSON.parse(localStorage.getItem('exhibitors') || '[]');
const meetings = JSON.parse(localStorage.getItem('meetings') || '[]');

const parseMinutes = (dateTimeStr) => {
  if (!dateTimeStr) return null;
  const d = new Date(dateTimeStr);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
};

// Gold-level exhibitors in AI tools category
const goldAi = exhibitors.filter(e => {
  if (!e) return false;
  if (e.sponsor_level !== 'gold') return false;
  if (!Array.isArray(e.categories)) return false;
  return e.categories.indexOf('ai_tools_and_platforms') !== -1;
});

// Bookmarked subset
const bookmarkedGoldAi = goldAi.filter(e => e.is_bookmarked);

// CP1 (0.5): User bookmarked at least two Gold-level exhibitors in AI tools category
checkpoints.push({ passed: bookmarkedGoldAi.length >= 2, weight: 0.5 });

// Qualifying demo meetings: exhibitor_demo, 15 minutes, Day 2, 14:00–16:00, with bookmarked Gold AI exhibitors
const bookmarkedIds = new Set(bookmarkedGoldAi.map(e => e.id));
const qualifyingMeetingExIds = new Set();

meetings.forEach(m => {
  if (!m) return;
  if (m.meeting_type !== 'exhibitor_demo') return;
  if (m.day_id !== 'day_2_june_13') return;
  if (m.duration_minutes !== 15) return;
  if (!m.exhibitor_id || !bookmarkedIds.has(m.exhibitor_id)) return;
  const mins = parseMinutes(m.start_datetime);
  if (mins === null) return;
  if (mins >= 14 * 60 && mins <= 16 * 60) {
    qualifyingMeetingExIds.add(m.exhibitor_id);
  }
});

// CP2 (0.5): User booked qualifying demos with at least two distinct bookmarked Gold AI tools exhibitors
checkpoints.push({ passed: qualifyingMeetingExIds.size >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const hotels = JSON.parse(localStorage.getItem('hotels') || '[]');

// Eligible hotels: ≤1 km, ≤$220, breakfast included
const eligible = hotels.filter(h => {
  if (!h) return false;
  if (typeof h.distance_km === 'number' && h.distance_km > 1.0) return false;
  if (typeof h.nightly_rate === 'number' && h.nightly_rate > 220) return false;
  if (!Array.isArray(h.amenities)) return false;
  return h.amenities.indexOf('breakfast_included') !== -1;
});

eligible.sort((a, b) => (a.distance_km || 0) - (b.distance_km || 0));
const nearest = eligible[0];

const savedEligible = eligible.filter(h => h.is_saved);

// CP1 (0.4): User saved at least one qualifying hotel (≤1 km, ≤$220, breakfast included)
checkpoints.push({ passed: savedEligible.length >= 1, weight: 0.4 });

// CP2 (0.6): User saved the nearest qualifying hotel to the venue
checkpoints.push({ passed: !!nearest && !!nearest.is_saved, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const onDemand = JSON.parse(localStorage.getItem('on_demand_sessions') || '[]');
const conferences = JSON.parse(localStorage.getItem('conferences') || '[]');

const nowYear = (new Date()).getFullYear();
let currentConf = conferences.find(c => c.current_year === nowYear);
if (!currentConf && conferences.length) {
  conferences.sort((a, b) => new Date(b.start_date).getTime() - new Date(a.start_date).getTime());
  currentConf = conferences[0];
}
const prevYear = currentConf ? currentConf.current_year - 1 : nowYear - 1;

// Candidates: last year's UX & Design sessions with duration ≤30 minutes
const candidates = onDemand.filter(s => {
  if (!s) return false;
  if (s.year !== prevYear) return false;
  if (s.track !== 'ux_and_design') return false;
  if (typeof s.duration_minutes === 'number' && s.duration_minutes > 30) return false;
  return true;
});

// Determine maximum popularity among candidates
let maxPop = null;
candidates.forEach(s => {
  const score = typeof s.popularity_score === 'number' ? s.popularity_score : 0;
  if (maxPop === null || score > maxPop) maxPop = score;
});

// Most popular sessions are those with popularity_score equal to maxPop
const mostPopular = maxPop === null ? [] : candidates.filter(s => {
  const score = typeof s.popularity_score === 'number' ? s.popularity_score : 0;
  return score === maxPop;
});

const watchlistedPopular = mostPopular.filter(s => s.in_watchlist);

// CP1 (0.5): User watchlisted at least one of last year's most popular short UX & Design sessions
checkpoints.push({ passed: watchlistedPopular.length >= 1, weight: 0.5 });

// CP2 (0.5): User watchlisted at least two such sessions
checkpoints.push({ passed: watchlistedPopular.length >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const meetings = JSON.parse(localStorage.getItem('meetings') || '[]');
const attendees = JSON.parse(localStorage.getItem('attendees') || '[]');

const attendeeById = {};
attendees.forEach(a => { if (a && a.id) attendeeById[a.id] = a; });

const parseMinutes = (dateTimeStr) => {
  if (!dateTimeStr) return null;
  const d = new Date(dateTimeStr);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
};

// Meetings satisfying per-meeting constraints: Day 2, 20 min, 13:00–15:00, with UX Designer
const qualifying = meetings.filter(m => {
  if (!m) return false;
  if (m.meeting_type !== 'attendee_meeting') return false;
  if (m.day_id !== 'day_2_june_13') return false;
  if (m.duration_minutes !== 20) return false;
  const mins = parseMinutes(m.start_datetime);
  if (mins === null) return false;
  if (mins < 13 * 60 || mins > 15 * 60) return false;
  const attendee = attendeeById[m.attendee_id];
  if (!attendee) return false;
  return attendee.role === 'UX Designer';
});

// Enforce distinct companies across selected meetings
const distinctCompanyMeetings = [];
const seenCompanies = new Set();
qualifying.forEach(m => {
  const attendee = attendeeById[m.attendee_id];
  const company = attendee && attendee.company ? attendee.company : '';
  if (!company) return;
  if (!seenCompanies.has(company)) {
    seenCompanies.add(company);
    distinctCompanyMeetings.push(m);
  }
});

// CP1 (0.3): At least one qualifying 20-min Day 2 meeting in the 13:00–15:00 window with a UX Designer from a unique company
checkpoints.push({ passed: distinctCompanyMeetings.length >= 1, weight: 0.3 });

// CP2 (0.3): At least two such meetings
checkpoints.push({ passed: distinctCompanyMeetings.length >= 2, weight: 0.3 });

// CP3 (0.4): At least three such meetings (full task completion)
checkpoints.push({ passed: distinctCompanyMeetings.length >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
